"use client";

import React from "react";
import { motion } from "framer-motion";
import { Quote } from "@/lib/types";
import { Share2, Copy, Check } from "lucide-react";
import { useToast } from "@/context/ToastContext";

interface ShareButtonProps {
  quote: Quote;
}

export function ShareButton({ quote }: ShareButtonProps) {
  const { addToast } = useToast();
  const [copied, setCopied] = React.useState(false);

  const shareText = `"${quote.content}" — ${quote.author}`;

  const handleShare = async () => {
    // Try native Web Share API first
    if (navigator.share) {
      try {
        await navigator.share({
          title: `Quote by ${quote.author}`,
          text: shareText,
          url: window.location.href,
        });
        addToast("Shared successfully!", "success");
        return;
      } catch (error) {
        // User cancelled or share failed, fall through to copy
        if ((error as Error).name === "AbortError") return;
      }
    }

    // Fallback to clipboard
    try {
      await navigator.clipboard.writeText(shareText);
      setCopied(true);
      addToast("Copied to clipboard!", "success");
      setTimeout(() => setCopied(false), 2000);
    } catch {
      addToast("Failed to copy", "error");
    }
  };

  return (
    <motion.button
      whileHover={{ scale: 1.1 }}
      whileTap={{ scale: 0.9 }}
      onClick={handleShare}
      className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-400 hover:text-primary-500 transition-all duration-200"
      aria-label="Share quote"
    >
      {copied ? (
        <Check className="w-5 h-5 text-green-500" />
      ) : (
        <Share2 className="w-5 h-5" />
      )}
    </motion.button>
  );
}
